export function navigationIconSvg(name, className = "") {
    const iconFile = navigationIconAssets[name];
    const svg = iconFile ? navigationSvgAssets[iconFile] : null;
    if (!svg)
        return "";
    const classes = `system-icon nav-inline-icon${className ? ` ${className}` : ""}`;
    return svg.replace("<svg ", `<svg class="${classes}" aria-hidden="true" focusable="false" `);
}
